if exists(select 1 from dmvt where ma_vt = @ma_vt) begin
  declare @unitCode varchar(32)
  select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end
  exec FastBusiness$Voucher$Issue$Item @unitCode, @ma_vt
  return
end









